package kotlinx.coroutines.flow.operators

import kotlinx.coroutines.testing.*
import kotlinx.coroutines.*
import kotlinx.coroutines.channels.*
import kotlinx.coroutines.flow.*
import kotlin.test.*
import kotlin.time.Duration.Companion.seconds

/**
 * Tests for callbackFlow closed with exception when chained with timeout.
 * See https://github.com/Kotlin/kotlinx.coroutines/issues/XXXX
 */
class TimeoutCallbackFlowTest : TestBase() {
    @Test
    fun testCallbackFlowCloseExceptionWithTimeout() = runTest {
        val testException = IllegalStateException("Test Exception")
        val flow = callbackFlow<Int> {
            close(testException)
            awaitClose()
        }.timeout(5.seconds)

        try {
            flow.collect()
            expectUnreached()
        } catch (e: IllegalStateException) {
            assertEquals("Test Exception", e.message)
        }
        finish(1)
    }

    @Test
    fun testCallbackFlowCloseExceptionWithTimeoutCustomException() = runTest {
        val flow = callbackFlow<Int> {
            close(TestException())
            awaitClose()
        }.timeout(5.seconds)

        assertFailsWith<TestException> { flow.collect() }
        finish(1)
    }

    @Test
    fun testCallbackFlowNormalCloseWithTimeout() = runTest {
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close()
            awaitClose()
        }.timeout(5.seconds)

        assertEquals(listOf(1, 2), flow.toList())
        finish(1)
    }

    @Test
    fun testChannelFlowCloseExceptionWithTimeout() = runTest {
        val testException = IllegalStateException("Test Exception")
        val flow = channelFlow<Int> {
            close(testException)
        }.timeout(5.seconds)

        try {
            flow.collect()
            expectUnreached()
        } catch (e: IllegalStateException) {
            assertEquals("Test Exception", e.message)
        }
        finish(1)
    }

    @Test
    fun testFlowCloseExceptionWithTimeoutAfterEmit() = runTest {
        val testException = IllegalStateException("Test Exception")
        val results = mutableListOf<Int>()
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close(testException)
            awaitClose()
        }.timeout(5.seconds)

        try {
            flow.collect { results.add(it) }
            expectUnreached()
        } catch (e: IllegalStateException) {
            assertEquals("Test Exception", e.message)
            assertEquals(listOf(1, 2), results)
        }
        finish(1)
    }
}
"}

